var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"이렇게나 무방비한 모습으로 제 앞에 서시다니......","JPN":"こんなに無防備な姿を私に見せるなんて……","ENG":"You're standing in front of me, looking so vulnerable.","TWN":"竟然用這樣毫無防備的樣子站在我面前…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"저를 만든 그 아이처럼, 영원한 고통 속에서 헤어나고 싶지 않으신가 보죠?","JPN":"私を作ったあの子のように、永遠の苦しみから解放されたくないみたいですね？","ENG":"Do you wish to join my maker, in a pit of everlasting pain?","TWN":"你能夠像我創造的那個孩子一樣，不奢求擺脫這個漫長且永遠的苦痛嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"채찍은 늘 준비되어 있답니다. 원하신다면 지금 바로 무릎을 꿇게 해 드릴 수도 있어요.","JPN":"ムチは常に用意しております。お望みでしたら、今すぐ跪かせることもできますよ。","ENG":"My whip is ready for use. I can make you kneel right now... if you want, that is.","TWN":"鞭子一直都準備著，如果你願意我會讓他跪在你面前。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"주인님이 제 발 아래서 귀엽게 지저귀는 광경이라면, 직원들에게 좋은 구경거리가 되겠군요.","JPN":"ご主人様が私の足元で可愛くおねだりする光景なら、社員たちにも良い見せ物になるでしょう。","ENG":"I'd love to see the look on the other employees' faces when they see you chirping happily under my feet. ","TWN":"如果主人在我腳下裝可愛，應該會變成員工們的笑柄。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"......후훗. 진지한 표정도 잘 어울리시네요.","JPN":"……ふふっ、真剣な顔もお似合いですよ。","ENG":"... Hah hah. You look handsome even when you're so serious. ","TWN":"……嘻嘻，認真的表情也很適合你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 저를 가지시겠다는 말씀이 어떤 뜻인지는 알고 계시겠죠?","JPN":"しかし、私を所有するということが、どういう意味なのかご存知ですよね？","ENG":"But you do know what it means to own me, don't you?","TWN":"不過，你應該知道《你想擁有我》是什麼意思吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"몇 번 만들어지든, 저는 오직 주인님의 피학성을 만족시키기 위해 존재한답니다.","JPN":"何回作り直されたとしても、私はご主人様のマゾヒズムを満足させるためにだけ存在します。","ENG":"It doesn't matter how many times I'm recreated. I only exist to satisfy my master's need for pain.","TWN":"即使被製造出無數次，我都是只為了滿足主人而存在的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"칼이 죄인의 위증을 밝히는 데 쓰이고, 형틀이 마녀를 정화하는 데 한몸 불사르듯 말이죠.","JPN":"剣は罪人の偽証を明かすために使われ、十字架が魔女の浄化に大いに役立つように。","ENG":"Just like the sword exists to reveal injustice, and the scaffold to purge witchcraft.","TWN":"利器常被用來查明罪人的僞證，自古刑具就被用來淨化女巫。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"설령 또다시 소멸을 맞이하더라도, 그 대신에 누군가에게 굴욕과 고통을 선사할 수 있다면...... 기꺼이 그럴 거예요.","JPN":"もし再び消滅を迎えるとしても、その代わりに、誰かに屈辱や苦しみを与えることができるなら……喜んでそうします。","ENG":"Even if I was destroyed again, I'd gladly welcome my death if I could humiliate and torment someone beforehand.","TWN":"即使未來某天我再次被消滅，但能夠因此給某人帶來屈辱和痛苦的話……我會甘願接受的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"물론 지금껏 많은 이들이 제게 굴복하지 않겠다고 호언장담했죠.","JPN":"もちろん、多くの人々は私に屈しないと豪語していました。","ENG":"A lot of people swore that they'd never submit to me.","TWN":"當然，到目前爲止，很多人總自豪的表示不會屈服於我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 결국 다들 쾌락에 흐느끼면서, 더 큰 고통을 탐닉하다 죽어 나갔답니다.","JPN":"しかし、結局みんな快楽に泣きながら、さらに大きな苦しみに溺れて死んでいきました。","ENG":"In the end, they all died, writhing in the excruciatingly delightful pain that I offered.","TWN":"但是最終大家都在快樂中哭泣，沉溺於更大的痛苦而死。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그러니 부디 신중하게 결정하시길.","JPN":"ですので、決めるのはどうか慎重にお願いします。","ENG":"So, please make your decision carefully.","TWN":"所以，請慎重考慮後再決定吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"제가 보여 드릴 공연은...... 목숨이 다하는 그날까지 영영 눈을 뗄 수 없을 테니까요.","JPN":"私が披露する公演は……命果てるその日まで、目をそらすことができませんので。","ENG":"You'll never forget the show that I will present to you.","TWN":"因為我接下來的演出…… 直到生命盡頭的那天爲止，你將永遠都無法移開視線的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};